BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?scenarioName ?reqName ?depType WHERE {
  ?scenario vocab:NamedElement_name ?scenarioName .
  FILTER(CONTAINS(LCASE(STR(?scenarioName)), "duration") && CONTAINS(LCASE(STR(?scenarioName)), "scenario"))
  FILTER(!CONTAINS(STR(?scenarioName), "."))

  {
    ?dep rdf:type ?depType .
    FILTER(?depType IN (vocab:verify, vocab:satisfy))
    {
      ?dep vocab:Dependency_client ?scenario .
      ?dep vocab:Dependency_supplier ?req .
    } UNION {
      ?dep vocab:Dependency_supplier ?scenario .
      ?dep vocab:Dependency_client ?req .
    }
    ?req vocab:NamedElement_name ?reqName .
  }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?scenario ?scenarioName ?dep ?depType ?depName ?target ?targetName ?targetType WHERE {
  ?scenario vocab:NamedElement_name ?scenarioName .
  FILTER(CONTAINS(LCASE(STR(?scenarioName)), "duration") && CONTAINS(LCASE(STR(?scenarioName)), "scenario"))
  FILTER(!CONTAINS(STR(?scenarioName), "."))

  ?dep vocab:DirectedRelationship_source ?scenario .
  ?dep rdf:type ?depType .
  ?dep vocab:DirectedRelationship_target ?target .
  OPTIONAL { ?dep vocab:NamedElement_name ?depName }
  OPTIONAL { ?target vocab:NamedElement_name ?targetName }
  OPTIONAL { ?target rdf:type ?targetType }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?clientName ?supplierName ?supplierType WHERE {
  ?verify rdf:type vocab:verify .
  ?verify vocab:Dependency_client ?client .
  ?verify vocab:Dependency_supplier ?supplier .
  OPTIONAL { ?client vocab:NamedElement_name ?clientName }
  OPTIONAL { ?supplier vocab:NamedElement_name ?supplierName }
  OPTIONAL { ?supplier rdf:type ?supplierType }
  FILTER(CONTAINS(LCASE(STR(?client)), "duration"))
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?scenarioName 
  (GROUP_CONCAT(DISTINCT ?timingReqName; separator=", ") AS ?matchingTimingRequirements)
WHERE {
  # Get all distinct duration scenarios (no dots in name = top-level)
  ?scenario vocab:NamedElement_name ?scenarioName .
  FILTER(CONTAINS(LCASE(STR(?scenarioName)), "duration") && CONTAINS(LCASE(STR(?scenarioName)), "scenario"))
  FILTER(!CONTAINS(STR(?scenarioName), "."))

  # Check for any verify link from this scenario or its children to a timing requirement
  OPTIONAL {
    {
      # Direct verify from scenario
      ?verify rdf:type vocab:verify .
      {
        ?verify vocab:Dependency_client ?scenario .
      } UNION {
        ?scenario vocab:Element_ownedElement ?child .
        ?verify vocab:Dependency_client ?child .
      }
      ?verify vocab:Dependency_supplier ?timingReq .
      ?timingReq vocab:NamedElement_name ?timingReqName .
    } UNION {
      # Name-based match to formalized timing requirements
      ?timingReq rdf:type vocab:block .
      ?timingReq vocab:NamedElement_name ?timingReqName .
      FILTER(CONTAINS(STR(?timingReq), "Formalized") && CONTAINS(STR(?timingReq), "Timing%2520Requirements"))
      # Match scenario name prefix to timing requirement name
      BIND(REPLACE(STR(?scenarioName), "%20Duration%20Scenario", "") AS ?scenarioBase)
      BIND(REPLACE(STR(?timingReqName), "%20Maximum%20Time", "") AS ?reqBase)
      FILTER(LCASE(?scenarioBase) = LCASE(?reqBase))
    }
  }
}
GROUP BY ?scenarioName
ORDER BY ?scenarioName

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?verifyClient ?verifyClientName ?verifySupplier ?verifySupplierName WHERE {
  ?verify rdf:type vocab:verify .
  FILTER(CONTAINS(STR(?verify), "Duration") || CONTAINS(STR(?verify), "duration"))
  ?verify vocab:Dependency_client ?verifyClient .
  ?verify vocab:Dependency_supplier ?verifySupplier .
  OPTIONAL { ?verifyClient vocab:NamedElement_name ?verifyClientName }
  OPTIONAL { ?verifySupplier vocab:NamedElement_name ?verifySupplierName }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?depType ?clientName ?supplierName WHERE {
  ?dep rdf:type ?depType .
  FILTER(?depType IN (vocab:verify, vocab:satisfy))
  ?dep vocab:Dependency_client ?client .
  ?dep vocab:Dependency_supplier ?supplier .
  {
    FILTER(CONTAINS(STR(?client), "Timing%20Requirements") || CONTAINS(STR(?supplier), "Timing%20Requirements"))
  }
  OPTIONAL { ?client vocab:NamedElement_name ?clientName }
  OPTIONAL { ?supplier vocab:NamedElement_name ?supplierName }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?client ?clientName WHERE {
  ?verify rdf:type vocab:verify .
  ?verify vocab:Dependency_client ?client .
  FILTER(CONTAINS(STR(?client), "Duration"))
  OPTIONAL { ?client vocab:NamedElement_name ?clientName }
}
LIMIT 10
